         // .NET 9 breaking change: StatusStrip default RenderMode changed from
         // System to Professional. Set explicitly to preserve .NET 8 behavior.
         _statusStrip.RenderMode = ToolStripRenderMode.System;
         Controls.Add(_statusStrip);
     }
 }

 /// <summary>
 /// UITypeEditor that uses IWindowsFormsEditorService.DropDownControl.
 /// </summary>
 public class SafeDropDownEditor : UITypeEditor
 {
     public override UITypeEditorEditStyle GetEditStyle(ITypeDescriptorContext? context)
         => UITypeEditorEditStyle.DropDown;

     public override object? EditValue(
         ITypeDescriptorContext? context,
         IServiceProvider? provider,
         object? value)
     {
         var editorService = provider?.GetService(typeof(IWindowsFormsEditorService))
             as IWindowsFormsEditorService;

         if (editorService is null)
             return value;

         var control = BuildDropDown(value);

         // .NET 9 breaking change: DropDownControl now throws ArgumentNullException
         // if the control argument is null. Guard against that.
         if (control is not null)
         {
             editorService.DropDownControl(control);
             value = control.Tag;
         }

         return value;
     }

     private static Control? BuildDropDown(object? currentValue)
     {
         var listBox = new ListBox();
         listBox.Items.AddRange(new object[] { "Option A", "Option B", "Option C" });
         listBox.Tag = currentValue;
         listBox.Click += (s, e) =>
         {
             if (s is ListBox lb && lb.SelectedItem is not null)
                 lb.Tag = lb.SelectedItem;
         };
         return listBox;
     }
 }

 /// <summary>
 /// P/Invoke declarations using the .NET 9-recommended [LibraryImport] source
 /// generator instead of the legacy [DllImport] attribute.
 /// LibraryImport gives compile-time marshalling, better AOT support, and avoids
 /// the runtime stub-generation overhead that DllImport uses.
 /// </summary>
 internal static partial class NativeMethods
 {
     // .NET 9 breaking change: [LibraryImport] is now the preferred interop
     // mechanism. [DllImport] still works but [LibraryImport] enables trimming
     // and Native AOT, which .NET 9 WinForms apps can now target.
     [LibraryImport("user32.dll", StringMarshalling = StringMarshalling.Utf16)]
     internal static partial int MessageBox(
         nint hWnd,
         string text,
         string caption,
         uint type);

     [LibraryImport("kernel32.dll", SetLastError = true)]
     [return: MarshalAs(UnmanagedType.Bool)]
     internal static partial bool Beep(uint frequency, uint duration);
 }
